module RefModule (
	input clk,
	input in,
	input reset,
	output reg rise);reg prev_in;

	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
		if (reset) begin
			prev_in <= 0;
			rise <= 0;
		end else begin
			rise <= !prev_in && in;
			prev_in <= in;
		end
	end

endmodule
